
<template>
  <view class="cart-page">
    <!-- 顶部区域 -->
    <view class="header">
      <view class="title">购物车</view>
      <view class="filter-search">
        <view class="filter-buttons">
          <view class="filter-button cursor-pointer">
            <text>全部</text>
            <uni-icons type="bottom" size="14" color="#666"></uni-icons>
          </view>
          <view class="filter-button cursor-pointer">
            <text>筛选</text>
            <uni-icons type="paperplane" size="14" color="#666"></uni-icons>
          </view>
        </view>
        <view class="search-box cursor-pointer">
          <uni-icons type="search" size="18" color="#999"></uni-icons>
          <text class="search-placeholder">查询商品</text>
        </view>
      </view>
    </view>

    <!-- 商品列表区域 -->
    <scroll-view class="cart-list" scroll-y="true">
      <view v-if="cartItems.length > 0">
        <view 
          v-for="(item, index) in cartItems" 
          :key="index" 
          class="cart-item"
        >
          <view class="select-box cursor-pointer" @click="toggleItemSelect(index)">
            <view class="circle" :class="{ selected: item.selected }">
              <uni-icons v-if="item.selected" type="checkmarkempty" size="16" color="#fff"></uni-icons>
            </view>
          </view>
          <image class="product-image" :src="item.image" mode="aspectFill"></image>
          <view class="product-info">
            <view class="product-name">{{ item.name }}</view>
            <view class="product-spec">{{ item.spec }}</view>
            <view class="product-price">¥{{ item.price.toFixed(2) }}</view>
            <view class="quantity-control">
              <view class="quantity-btn cursor-pointer" @click="decreaseQuantity(index)">
                <uni-icons type="minus" size="16" color="#666"></uni-icons>
              </view>
              <view class="quantity">{{ item.quantity }}</view>
              <view class="quantity-btn cursor-pointer" @click="increaseQuantity(index)">
                <uni-icons type="plus" size="16" color="#666"></uni-icons>
              </view>
            </view>
          </view>
        </view>
      </view>
      <view v-else class="empty-cart">
        <image class="empty-cart-image" :src="emptyCartImage" mode="aspectFit"></image>
        <text class="empty-cart-text">购物车还是空的，快去挑选商品吧</text>
        <view class="go-shopping-btn cursor-pointer">去购物</view>
      </view>
    </scroll-view>

    <!-- 底部结算栏 -->
    <view class="checkout-bar">
      <view class="select-all cursor-pointer" @click="toggleSelectAll">
        <view class="circle" :class="{ selected: allSelected }">
          <uni-icons v-if="allSelected" type="checkmarkempty" size="16" color="#fff"></uni-icons>
        </view>
        <text>全选</text>
      </view>
      <view class="total-amount">
        <text>合计：</text>
        <text class="price">¥{{ totalAmount.toFixed(2) }}</text>
      </view>
      <view class="checkout-btn cursor-pointer" @click="checkout">
        <text>去结算 ({{ selectedCount }})</text>
      </view>
    </view>

    <!-- 底部导航栏 -->
    <view class="tab-bar">
      <view class="tab-item cursor-pointer">
        <uni-icons type="home" size="24" color="#999"></uni-icons>
        <text class="tab-text">首页</text>
      </view>
      <view class="tab-item cursor-pointer">
        <uni-icons type="list" size="24" color="#999"></uni-icons>
