<script lang="ts" setup>
import { ref, computed } from 'vue';

// 空购物车图片
const emptyCartImage = 'https://readdy.ai/api/search-image?query=Empty%20shopping%20cart%20illustration%2C%20minimalist%20design%2C%20soft%20colors%2C%20simple%20outline%20drawing%2C%20clean%20background%2C%20shopping%20basket%20with%20leaf%20motif%2C%20eco-friendly%20style%2C%20suitable%20for%20elderly%20users%2C%20clear%20visual%20hierarchy%2C%20gentle%20color%20palette%2C%20uncluttered%20composition%2C%20centered%20subject&width=300&height=300&seq=empty-cart-001&orientation=squarish';

// 购物车商品数据
const cartItems = ref([
  {
    id: 1,
    name: '有机红富士苹果',
    spec: '5斤装/箱',
    price: 39.9,
    quantity: 1,
    selected: true,
    image: 'https://readdy.ai/api/search-image?query=Organic%20red%20fuji%20apples%2C%20fresh%20farm%20produce%2C%20natural%20lighting%2C%20vibrant%20red%20color%2C%20crisp%20and%20juicy%20appearance%2C%20high-quality%20close-up%20photograph%2C%20clean%20white%20background%2C%20farm%20to%20table%20concept%2C%20healthy%20food%20photography%2C%20isolated%20product%20shot&width=200&height=200&seq=apple-001&orientation=squarish'
  },
  {
    id: 2,
    name: '新鲜黄皮香蕉',
    spec: '2.5kg/把',
    price: 15.8,
    quantity: 2,
    selected: true,
    image: 'https://readdy.ai/api/search-image?query=Fresh%20yellow%20bananas%2C%20bunch%20of%20ripe%20bananas%2C%20natural%20lighting%2C%20vibrant%20yellow%20color%2C%20farm%20fresh%20produce%2C%20high-quality%20close-up%20photograph%2C%20clean%20white%20background%2C%20farm%20to%20table%20concept%2C%20healthy%20tropical%20fruit%2C%20isolated%20product%20shot&width=200&height=200&seq=banana-001&orientation=squarish'
  },
  {
    id: 3,
    name: '新鲜有机胡萝卜',
    spec: '500g/份',
    price: 8.5,
    quantity: 1,
    selected: false,
    image: 'https://readdy.ai/api/search-image?query=Fresh%20organic%20carrots%2C%20vibrant%20orange%20color%2C%20farm%20fresh%20vegetables%20with%20green%20tops%2C%20natural%20lighting%2C%20crisp%20and%20healthy%20appearance%2C%20high-quality%20close-up%20photograph%2C%20clean%20white%20background%2C%20farm%20to%20table%20concept%2C%20isolated%20product%20shot&width=200&height=200&seq=carrot-001&orientation=squarish'
  },
  {
    id: 4,
    name: '农家散养土鸡蛋',
    spec: '10枚/盒',
    price: 16.9,
    quantity: 1,
    selected: true,
    image: 'https://readdy.ai/api/search-image?query=Farm%20fresh%20free-range%20eggs%2C%20brown%20eggs%20in%20carton%2C%20natural%20lighting%2C%20organic%20farm%20produce%2C%20high-quality%20close-up%20photograph%2C%20clean%20white%20background%2C%20farm%20to%20table%20concept%2C%20healthy%20food%20photography%2C%20isolated%20product%20shot&width=200&height=200&seq=eggs-001&orientation=squarish'
  },
  {
    id: 5,
    name: '新鲜西红柿',
    spec: '1kg/份',
    price: 9.9,
    quantity: 2,
    selected: false,
    image: 'https://readdy.ai/api/search-image?query=Fresh%20red%20tomatoes%2C%20ripe%20and%20juicy%20tomatoes%2C%20natural%20lighting%2C%20vibrant%20red%20color%2C%20farm%20fresh%20produce%2C%20high-quality%20close-up%20photograph%2C%20clean%20white%20background%2C%20farm%20to%20table%20concept%2C%20healthy%20vegetables%2C%20isolated%20product%20shot&width=200&height=200&seq=tomato-001&orientation=squarish'
  }
]);

// 计算属性：全选状态
const allSelected = computed(() => {
  return cartItems.value.length > 0 && cartItems.value.every(item => item.selected);
});

// 计算属性：已选商品数量
const selectedCount = computed(() => {
  return cartItems.value.filter(item => item.selected).length;
});

// 计算属性：合计金额
const totalAmount = computed(() => {
  return cartItems.value.reduce((sum, item) => {
    return item.selected ? sum + item.price * item.quantity : sum;
  }, 0);
});

// 切换商品选中状态
const toggleItemSelect = (index: number) => {
  cartItems.value[index].selected = !cartItems.value[index].selected;
};

// 切换全选状态
const toggleSelectAll = () => {
  const newStatus = !allSelected.value;
  cartItems.value.forEach(item => {
    item.selected = newStatus;
  });
};

// 增加商品数量
const increaseQuantity = (index: number) => {
  if (cartItems.value[index].quantity < 99) {
    cartItems.value[index].quantity += 1;
  }
};

// 减少商品数量
const decreaseQuantity = (index: number) => {
  if (cartItems.value[index].quantity > 1) {
    cartItems.value[index].quantity -= 1;
  }
};

// 去结算
const checkout = () => {
  if (selectedCount.value === 0) {
    uni.showToast({
      title: '请选择要结算的商品',
      icon: 'none'
    });
    return;
  }
  
  uni.showToast({
    title: '正在前往结算页面',
    icon: 'none'
  });
  // 实际应用中这里会跳转到结算页面
};
</script>

